#include <stdio.h>
#include <stdlib.h>

int minCost(int* cuts, int n, int c) {
    int** dp = (int**)malloc((c + 2) * sizeof(int*));
    for (int i = 0; i < c + 2; i++) {
        dp[i] = (int*)malloc((c + 2) * sizeof(int));
    }

    for (int i = 1; i <= c + 1; i++) {
        for (int j = i; j <= c + 1; j++) {
            if (i == j) {
                dp[i][j] = 0;
            } else {
                dp[i][j] = INT_MAX;
                for (int k = i + 1; k < j; k++) {
                    dp[i][j] = (dp[i][j] < dp[i][k] + dp[k][j] + cuts[j] - cuts[i - 1]) ? dp[i][j] : dp[i][k] + dp[k][j] + cuts[j] - cuts[i - 1];
                }
            }
        }
    }

    int result = dp[1][c + 1];
    for (int i = 0; i < c + 2; i++) {
        free(dp[i]);
    }
    free(dp);
    return result;
}

int main() {
    int n, c;
    scanf("%d %d", &n, &c);
    int* cuts = (int*)malloc((c + 2) * sizeof(int));
    cuts[0] = 0;
    cuts[c + 1] = n;
    for (int i = 1; i <= c; i++) {
        scanf("%d", &cuts[i]);
    }

    printf("%d\n", minCost(cuts, n, c));

    free(cuts);
    return 0;
}

